        assert_eq!(from_roman(&roman), Ok(value), "{value} -> {roman} -> {value}");

        let reparsed = from_roman(&roman).expect("formatted numeral should parse");
        assert_eq!(to_roman(reparsed), Ok(roman.clone()), "{roman} should stay canonical");
    }
}

